import React from "react";

function ProductCard({ product }) {
  return (
    <div style={styles.card}>
      <img src={product.image} alt={product.name} style={{ width: "100%", height: "150px", objectFit: "cover" }} />
      <h3>{product.name}</h3>
      <p>${product.price}</p>
      <button style={styles.btn}>Add to Cart</button>
    </div>
  );
}

const styles = {
  card: { border: "1px solid #ccc", borderRadius: "8px", padding: "10px", textAlign: "center", width: "200px" },
  btn: { background: "#007bff", color: "white", padding: "5px 10px", border: "none", borderRadius: "5px", cursor: "pointer" }
};

export default ProductCard;
